import{_ as o,o as a,c as l,a2 as s}from"./chunks/framework.BA5E086R.js";const p=JSON.parse('{"title":"博客动画增强 — 设计规范","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-06-28-blog-animation-design.md","filePath":"superpowers/specs/2026-06-28-blog-animation-design.md"}'),r={name:"superpowers/specs/2026-06-28-blog-animation-design.md"};function n(t,e,i,c,d,h){return a(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="博客动画增强-—-设计规范" tabindex="-1">博客动画增强 — 设计规范 <a class="header-anchor" href="#博客动画增强-—-设计规范" aria-label="Permalink to &quot;博客动画增强 — 设计规范&quot;">​</a></h1><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><ul><li><strong>目标</strong>: 为 MyBlogs（Peter的博客）全站添加生动而贴合终端美学的动画效果</li><li><strong>技术选型</strong>: GSAP 3 + ScrollTrigger + TextPlugin</li><li><strong>设计原则</strong>: 动画服务于&quot;暗色终端&quot;主题身份，增强阅读体验而非干扰内容</li></ul><hr><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><h3 id="依赖" tabindex="-1">依赖 <a class="header-anchor" href="#依赖" aria-label="Permalink to &quot;依赖&quot;">​</a></h3><ul><li><code>gsap</code> ^3.12.0 — 动画引擎（含 ScrollTrigger、TextPlugin）</li></ul><h3 id="文件结构" tabindex="-1">文件结构 <a class="header-anchor" href="#文件结构" aria-label="Permalink to &quot;文件结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/.vitepress/theme/</span></span>
<span class="line"><span>├── index.ts                     # ✏️ 注册 GSAP 插件 + v-reveal 指令</span></span>
<span class="line"><span>├── style.css                    # ✏️ 删改旧动画，新增动画辅助样式</span></span>
<span class="line"><span>├── composables/</span></span>
<span class="line"><span>│   ├── useScrollReveal.ts       # ✨ ScrollTrigger 滚动渐现 composable</span></span>
<span class="line"><span>│   └── useTypewriter.ts         # ✨ GSAP 打字机 composable</span></span>
<span class="line"><span>├── directives/</span></span>
<span class="line"><span>│   └── vReveal.ts               # ✨ v-reveal 自定义指令</span></span>
<span class="line"><span>├── components/</span></span>
<span class="line"><span>│   ├── MatrixRain.vue           # ✨ Matrix 微光雨 Canvas 组件</span></span>
<span class="line"><span>│   ├── ScrollProgress.vue       # ✨ 阅读进度条</span></span>
<span class="line"><span>│   └── PageTransition.vue       # ✨ 页面切换过渡</span></span>
<span class="line"><span>└── animations/</span></span>
<span class="line"><span>    └── presets.ts               # ✨ 预设 GSAP 动画配置</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docs/index.md                    # ✏️ 使用新 composable + MatrixRain</span></span></code></pre></div><h3 id="全局注册流程" tabindex="-1">全局注册流程 <a class="header-anchor" href="#全局注册流程" aria-label="Permalink to &quot;全局注册流程&quot;">​</a></h3><ol><li><code>index.ts</code> 中导入 GSAP 插件，注册为 Vue 全局属性 <code>$gsap</code></li><li>注册 <code>v-reveal</code> 自定义指令</li><li>可选在 <code>config.ts</code> 中无需变更——所有组件在 Markdown <code>&lt;script setup&gt;</code> 中按需引入</li></ol><hr><h2 id="动画效果明细" tabindex="-1">动画效果明细 <a class="header-anchor" href="#动画效果明细" aria-label="Permalink to &quot;动画效果明细&quot;">​</a></h2><h3 id="g1-·-页面切换过渡" tabindex="-1">G1 · 页面切换过渡 <a class="header-anchor" href="#g1-·-页面切换过渡" aria-label="Permalink to &quot;G1 · 页面切换过渡&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>PageTransition.vue</code> — <code>VitePress</code> 没有暴露 <code>&lt;router-view&gt;</code>，采用替代方案：监听路由变化，对 <code>.VPDoc</code> 容器做 GSAP <code>fromTo</code></li><li><strong>效果</strong>: 内容区 opacity 0→1，y 15px→0，duration 0.25s，ease <code>power2.out</code></li><li><strong>注意</strong>: 首次加载不触发过渡</li></ul><h3 id="g2-·-导航栏滚动阴影" tabindex="-1">G2 · 导航栏滚动阴影 <a class="header-anchor" href="#g2-·-导航栏滚动阴影" aria-label="Permalink to &quot;G2 · 导航栏滚动阴影&quot;">​</a></h3><ul><li><strong>实现</strong>: CSS 方案 — 用 <code>scroll()</code> 驱动的动画或监听 <code>window.scrollY</code> 给 <code>.VPNavBar</code> 动态添加 <code>scrolled</code> class</li><li><strong>效果</strong>: 滚动超过 20px 时，导航栏底部浮现 <code>0 1px 8px rgba(0,0,0,0.4)</code> 阴影</li><li><strong>transition</strong>: 0.3s</li></ul><h3 id="g3-·-链接下划线滑动" tabindex="-1">G3 · 链接下划线滑动 <a class="header-anchor" href="#g3-·-链接下划线滑动" aria-label="Permalink to &quot;G3 · 链接下划线滑动&quot;">​</a></h3><ul><li><strong>实现</strong>: 纯 CSS — <code>.vp-doc a</code> 使用 <code>::after</code> 伪元素 + <code>transform: scaleX(0)</code> → <code>scaleX(1)</code> on hover</li><li><strong>效果</strong>: 下划线从左侧滑入，颜色 <code>--accent</code>，替代现有 <code>border-bottom: dashed</code></li></ul><h3 id="g4-·-元素滚动渐现" tabindex="-1">G4 · 元素滚动渐现 <a class="header-anchor" href="#g4-·-元素滚动渐现" aria-label="Permalink to &quot;G4 · 元素滚动渐现&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>v-reveal</code> 指令 + <code>useScrollReveal</code> composable（底层用 ScrollTrigger）</li><li><strong>效果</strong>: 目标元素进入视口时，从 <code>opacity: 0, y: 30px</code> 渐现到原位</li><li><strong>配置</strong>: <code>threshold: 0.15</code>, <code>duration: 0.5s</code>, <code>ease: power2.out</code></li><li><strong>用法</strong>: <code>&lt;h2 v-reveal&gt;标题&lt;/h2&gt;</code> 或 <code>&lt;div v-reveal=&quot;{ y: 20 }&quot;&gt;...&lt;/div&gt;</code></li></ul><h3 id="g5-·-滚动进度条" tabindex="-1">G5 · 滚动进度条 <a class="header-anchor" href="#g5-·-滚动进度条" aria-label="Permalink to &quot;G5 · 滚动进度条&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>ScrollProgress.vue</code> — <code>position: fixed; top: 0; height: 2px; background: var(--accent)</code>，ScrollTrigger 更新 <code>scaleX</code></li><li><strong>效果</strong>: 极细琥珀色线横贯页面顶部，从左到右反映阅读进度</li><li><strong>z-index</strong>: 高于导航栏</li></ul><h3 id="h1-·-gsap-重写打字机" tabindex="-1">H1 · GSAP 重写打字机 <a class="header-anchor" href="#h1-·-gsap-重写打字机" aria-label="Permalink to &quot;H1 · GSAP 重写打字机&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>useTypewriter</code> composable — 接收目标字符串，返回 <code>displayText</code>（ref）</li><li><strong>效果</strong>: 逐字打印，每个字符间隔 50-90ms 随机微延迟，光标平滑闪烁</li><li><strong>替代</strong>: 现有 <code>setInterval</code> 实现</li></ul><h3 id="h2-·-个人介绍交错浮现" tabindex="-1">H2 · 个人介绍交错浮现 <a class="header-anchor" href="#h2-·-个人介绍交错浮现" aria-label="Permalink to &quot;H2 · 个人介绍交错浮现&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>&lt;div v-reveal=&quot;{ stagger: 0.1 }&quot;&gt;</code> 包裹介绍区域各子元素</li><li><strong>效果</strong>: 打字完成后内容显示，名字→描述→列表→footer 依次从下方滑入，每个延迟 0.1s</li></ul><h3 id="h3-·-文章列表项-hover-抬起" tabindex="-1">H3 · 文章列表项 hover 抬起 <a class="header-anchor" href="#h3-·-文章列表项-hover-抬起" aria-label="Permalink to &quot;H3 · 文章列表项 hover 抬起&quot;">​</a></h3><ul><li><strong>实现</strong>: 纯 CSS — <code>.post-list li:hover</code> 添加 <code>transform: translateY(-2px)</code> + 左侧 <code>::before</code> 伪元素琥珀色竖线</li><li><strong>效果</strong>: 悬浮行轻微上浮，左侧出现 <code>2px solid var(--accent)</code> 指示器</li></ul><h3 id="p1-·-标题入场" tabindex="-1">P1 · 标题入场 <a class="header-anchor" href="#p1-·-标题入场" aria-label="Permalink to &quot;P1 · 标题入场&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>v-reveal</code> 指令作用于 <code>.vp-doc h1, .vp-doc h2, .vp-doc h3</code></li><li><strong>效果</strong>: 标题从下方 20px 滑入，h1/h2/h3 分别延迟 0/0.05/0.1s（通过 CSS 或指令参数）</li></ul><h3 id="p2-·-代码块终端窗口" tabindex="-1">P2 · 代码块终端窗口 <a class="header-anchor" href="#p2-·-代码块终端窗口" aria-label="Permalink to &quot;P2 · 代码块终端窗口&quot;">​</a></h3><ul><li><strong>实现</strong>: 纯 CSS — <code>div[class*=&#39;language-&#39;]</code> 添加 <code>::before</code> 三色圆点（红 #FF5F57 / 黄 #FEBC2E / 绿 #28C840）</li><li><strong>效果</strong>: hover 时代码块 <code>transform: scale(1.01)</code>，<code>transition: 0.2s</code></li></ul><h3 id="p3-·-blockquote-滑入" tabindex="-1">P3 · Blockquote 滑入 <a class="header-anchor" href="#p3-·-blockquote-滑入" aria-label="Permalink to &quot;P3 · Blockquote 滑入&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>v-reveal</code> 指令作用于 <code>blockquote</code>，from <code>x: -20px</code></li><li><strong>效果</strong>: 引用块从左侧滑入，左边框先出现</li></ul><h3 id="x1-·-matrix-微光雨" tabindex="-1">X1 · Matrix 微光雨 <a class="header-anchor" href="#x1-·-matrix-微光雨" aria-label="Permalink to &quot;X1 · Matrix 微光雨&quot;">​</a></h3><ul><li><strong>实现</strong>: <code>&lt;MatrixRain&gt;</code> Vue 组件，Canvas 2D 绘制</li><li><strong>字符集</strong>: 键盘符号 <code>{}[]()/&lt;&gt;$*#@.</code> + 少量十六进制数字</li><li><strong>颜色</strong>: <code>#7EB87E</code>（终端绿），主体透明度 0.06-0.10，头部字符 0.15</li><li><strong>速度</strong>: 0.3-0.8 px/frame 随机，偶尔停顿</li><li><strong>密度</strong>: 10-12 列（移动端减半）</li><li><strong>性能</strong>: <code>IntersectionObserver</code> — 页面不可见时暂停 <code>requestAnimationFrame</code></li><li><strong>位置</strong>: 首页 <code>position: fixed; z-index: -1</code>，不影响交互</li></ul><hr><h2 id="性能约束" tabindex="-1">性能约束 <a class="header-anchor" href="#性能约束" aria-label="Permalink to &quot;性能约束&quot;">​</a></h2><ol><li>所有 ScrollTrigger 实例在组件 <code>onUnmounted</code> 时 <code>kill()</code></li><li>Matrix 雨在视口不可见时暂停（<code>IntersectionObserver</code>）</li><li>移动端 Matrix 密度减半至 5-6 列</li><li>GSAP 按需引入：<code>gsap</code> + <code>ScrollTrigger</code> + <code>TextPlugin</code></li><li><code>prefers-reduced-motion</code> 时降级所有动画为静态</li></ol><hr><h2 id="回滚策略" tabindex="-1">回滚策略 <a class="header-anchor" href="#回滚策略" aria-label="Permalink to &quot;回滚策略&quot;">​</a></h2><ul><li>GSAP 和 MatrixRain 作为可选增强，出错时不影响页面正常渲染</li><li><code>v-reveal</code> 指令在 JS 失败时元素保持可见（<code>opacity: 1</code> 作为 fallback）</li><li>可通过注释 <code>index.ts</code> 中的插件注册行快速禁用全部动画</li></ul><hr><p><em>创建时间: 2026-06-28</em></p>`,45)])])}const u=o(r,[["render",n]]);export{p as __pageData,u as default};
